VALUES
  ('judicial-d35ec6db-moex-00117', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於甲於2024年1月1日所立遺囑之效力敘述，何者正確？ 甲為2005年12月31日出生，其遺囑無效 甲為2008年12月31日出生，其遺囑有效 甲為2007年5月31日出生，所立遺囑未經其法定代理人同意，其遺囑無效 甲為2007年12月31日出生，其法定代理人拒絕承認甲所立遺囑，其遺囑無效', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00118', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於特留分之敘述，何者正確？ 繼承人喪失繼承權，但仍享有特留分 繼承開始後，特留分權利不得自由拋棄 拋棄特留分，不等於拋棄繼承 拋棄特留分後，其他特留分權利人之特留分當然因而增加', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00119', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列何者非屬應以法律或法規命令規定之事項？', '["人民之權利、義務", "獨立機關之組織", "其他重要事項", "對人民僅產生不便或輕微影響之細節性、技術性次要事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00120', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列何者並非行政程序法明文規定的行政法一般原理原則？', '["明確性原則", "平等原則", "誠信原則", "公私協力原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00121', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於依法行政與裁量，下列敘述何者正確？', '["如法律規定「情節重大者，得令其停工或停業」，係指主管機關僅能在「停工或停業」中擇一處罰，並無 不予處罰的權限", "法條中使用「得」字者，均可解為裁量之規定", "行政機關依裁量權所為罰鍰處分，違反最高科處5倍之罰鍰時，僅可由行政法院撤銷之", "受理訴願機關對於下級機關所為裁量處分之當否，無權進行審查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00122', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依身心障礙者權益保障法第43條第2項規定，民營事業員工總數達法定人數以上，而未進用有就業能力 之身心障礙者達法定人數時，應定期向主管機關之身心障礙者就業基金繳納差額補助費，此差額補助費之 性質為何？', '["罰鍰", "規費", "稅捐", "代金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00123', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列事項不適用行政程序法之程序規定，其中何者屬「特別法律關係」之典型類型？', '["有關外交行為、軍事行為或國家安全保障事項之行為", "對公務員所為之人事行政行為", "外國人出、入境、難民認定及國籍變更之行為", "刑事案件犯罪偵查程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00124', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依地方制度法規定，關於自治法規之敘述，下列何者正確？', '["自治法規經地方立法機關通過，並由各該行政機關公布者，稱自治規則", "自治法規由地方行政機關訂定，並發布或下達者，稱自治條例", "關於地方自治團體及所營事業機構之組織，應以自治規則訂定之", "委辦規則應函報委辦機關核定後發布之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00125', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依中央行政機關組織基準法規定，關於行政機關之名稱，下列敘述何者正確？', '["一級機關之名稱使用「部」", "二級機關之名稱使用「委員會」", "三級機關之名稱使用「分局」", "四級機關之名稱使用「署」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00126', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於地方制度法中之用詞定義，下列敘述何者正確？', '["委辦事項是指地方自治團體負政策規劃及行政執行責任之事項", "自治事項是指地方自治團體執行上級政府交付辦理之非屬該團體事務", "核定是指上級政府對於下級政府所陳報之事項，有權審查並作成決定，以完成該事項之法定效力", "備查是指下級政府得自為立法並執行，但無法自行完成法定效力，而應送上級政府審查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
